good-example.code-block:
// Strategy 1: URI path — separate controllers per major version
import io.micronaut.http.annotation.*;

@Controller("/api/v1/products")
public class ProductControllerV1 {

    @Get("/{id}")
    public ProductDtoV1 get(String id) {
        return new ProductDtoV1("widget", 9.99);
    }
}

@Controller("/api/v2/products")
public class ProductControllerV2 {

    @Get("/{id}")
    public ProductDtoV2 get(String id) {
        return new ProductDtoV2("widget", new Money(999, "USD"));
    }
}

record ProductDtoV1(String name, double price) { }
record ProductDtoV2(String name, Money price) { }
record Money(int amountCents, String currency) { }

// Strategy 2: Header — same path, versioned by required header (route match)
import io.micronaut.http.annotation.*;

@Controller("/api/products")
public class ProductByHeaderV1 {

    @Get(value = "/{id}", headers = "X-API-Version=1")
    public ProductDtoV1 getV1(String id) {
        return new ProductDtoV1("widget", 9.99);
    }
}

@Controller("/api/products")
public class ProductByHeaderV2 {

    @Get(value = "/{id}", headers = "X-API-Version=2")
    public ProductDtoV2 getV2(String id) {
        return new ProductDtoV2("widget", new Money(999, "USD"));
    }
}

record ProductDtoV1(String name, double price) { }
record ProductDtoV2(String name, Money price) { }
record Money(int amountCents, String currency) { }

// Strategy 3: Vendor media type — match on Accept / produces
import io.micronaut.http.HttpResponse;
import io.micronaut.http.MediaType;
import io.micronaut.http.annotation.*;

@Controller("/api/products")
public class ProductMediaVersioned {

    static final String V1 = "application/vnd.example.product+json;version=1";
    static final String V2 = "application/vnd.example.product+json;version=2";

    @Get(value = "/{id}", produces = V1)
    public HttpResponse<ProductDtoV1> getV1(String id) {
        return HttpResponse.ok(new ProductDtoV1("widget", 9.99));
    }

    @Get(value = "/{id}", produces = V2)
    public HttpResponse<ProductDtoV2> getV2(String id) {
        return HttpResponse.ok(new ProductDtoV2("widget", new Money(999, "USD")));
    }
}

record ProductDtoV1(String name, double price) { }
record ProductDtoV2(String name, Money price) { }
record Money(int amountCents, String currency) { }

